strings:////records=["xxx.xxx\"\"yyy..yyy"]////WhenpushingtoRoute53,thiscouldbeconvertedto:////"xxx..xx""xyyy...y""yy"////Ifyouwanttoaddthisfeature,makesuretofollowallthequotingrulesin//<https://tools.ietf.org/html/rfc1464#section-2>.Ifyoumakeamistake,people//mightenduprelyingonthatmistakesofixingitwouldbeabreakingchange.funcexpandTxtEntry(sstring)string{last:=len(s)-1func=s[1:last]}returns}funcflattenTxtEntry(sstring)string{returnfmt.Sprintf(`"%s"`,s)}func